        <h2 style={{ color: 'red', marginBottom: 10 }}>🚨 Rescue {needyPlayer.name}!</h2>
        <p style={{ fontWeight: 'bold', fontSize: 18 }}>{needyPlayer.name} cannot pay ${rentAmount} rent.</p>
        <div style={{ margin: '18px 0', background: '#ffeaea', borderRadius: 8, padding: 12 }}>
          <div style={{ fontWeight: 'bold', marginBottom: 6 }}>Rescue Options:</div>
          <div style={{ textAlign: 'left', marginLeft: 20 }}>
            <div>1. <b>Buy Zchut</b>: {zchutAvailable} Zchut available. Other players can pay any amount to {needyPlayer.name} and receive double Zchut points (up to {zchutAvailable} Zchut).</div>
            <div>2. <b>Buy Property</b>: (Coming soon) Buy property at a recommended price.</div>
          </div>
        </div>
        <div style={{ margin: '10px 0 16px 0' }}>
          <div style={{ fontWeight: 'bold' }}>Players:</div>
          <ul style={{ listStyle: 'none', padding: 0, margin: 0 }}>
            {players.filter(p => p.index !== needyPlayer.index).map((p, i) => (
              <li key={p.index} style={{ margin: '6px 0', color: p.color }}>
                {p.name} (${p.money} money, {p.zchutPoints || 0} Zchut)
              </li>
