          </ul>
        </div>
        <button style={{ ...modalStyles.button, backgroundColor: '#dc3545' }} onClick={onRescue}>Buy Zchut</button>
        <button style={modalStyles.button} onClick={onClose}>Close</button>
      </div>
    </div>
  );
}

